#include<bits/stdc++.h>
using namespace std;
vector<int>newv, neww;
//         价值  重量 
int dp[40005];
int main()
{
	int n, k;
	cin >> n >> k;
	for(int i = 1; i <= n; i++){
		int v, w, m;
		cin >> v >> w >> m;
		int x = m, k = 1;
		while(x >= k){
			newv.push_back(k * v);
			neww.push_back(k * w);
			x -= k;
			k *= 2;
		}
		if(x)newv.push_back(x * v), neww.push_back(x * w);
	}
	for(int i = 0; i < neww.size(); i++){
		for(int j = k; j >= neww[i]; j--){
			dp[j] = max(dp[j], dp[j - neww[i]] + newv[i]);
		}
	}
	cout << dp[k];
}
